#!/usr/bin/env node

/**
 *
 * Custom Storybook LLMs Extractor for Storybook 9
 * WARNING: The following code has been mostly generated by LLMs.
 *
 * This script extracts comprehensive documentation from Storybook 9 builds
 * including props, types, and descriptions, generating a single LLM-friendly
 * file following the llmstxt.org specification.
 *
 * It is inspired by the @fluentui/storybook-llms-extractor package which works only for Storybook 7 and 8.
 */

import { readFileSync, writeFileSync, existsSync, readdirSync } from "fs";
import { join, dirname, basename } from "path";
import { fileURLToPath } from "url";
import { execSync } from "child_process";
import process from "node:process";

const __dirname = dirname(fileURLToPath(import.meta.url));

function getCurrentBranch() {
    return execSync("git branch --show-current", { encoding: "utf-8" }).trim();
}

const currentBranch = getCurrentBranch();
const isBeta = currentBranch === "beta";

const CONFIG = {
    distPath: "../netlify/dist",
    summaryBaseUrl: isBeta
        ? "https://beta.svelte.stackoverflow.design"
        : "https://svelte.stackoverflow.design",
    summaryTitle: "Stacks Svelte",
    summaryDescription: "Stacks Svelte Components Documentation",
};
const { distPath, summaryBaseUrl, summaryTitle, summaryDescription } = CONFIG;

export function parseStorybookIndex(distPath) {
    const content = readFileSync(join(distPath, "index.json"), "utf-8");
    return JSON.parse(content);
}

export function groupStoriesByComponent(entries) {
    const groups = new Map();

    Object.values(entries).forEach(({ title, type, id, importPath, name }) => {
        if (!groups.has(title)) {
            groups.set(title, { title, docs: null, stories: [], importPath });
        }

        const group = groups.get(title);
        if (type === "docs") group.docs = { id };
        else if (type === "story") group.stories.push({ id, name });
    });

    return Array.from(groups.values());
}

export function cleanJSDoc(jsdoc) {
    return jsdoc
        .split("\n")
        .map((line) => line.replace(/^\s*\*\s?/, "").trim())
        .filter((line) => line && !line.startsWith("@"))
        .join(" ")
        .trim();
}

export function cleanType(type) {
    return type
        .replace(/\s+/g, " ")
        .replace(/\| undefined$/, "")
        .trim();
}

export function extractPropsFromInterface(content) {
    const match = content.match(
        /(?:export\s+)?(?:interface|type)\s+Props\s*(?:extends\s+[^{]*)?\{/s
    );
    if (!match) return [];

    let braceCount = 1;
    let idx = match.index + match[0].length;
    let propsContent = "";

    while (idx < content.length && braceCount > 0) {
        const char = content[idx++];
        if (char === "{") braceCount++;
        if (char === "}") braceCount--;
        if (braceCount > 0) propsContent += char;
    }

    const cleaned = propsContent
        .replace(/\/\/[^\n]*/g, "")
        .replace(/\/\*(?!\*).*?\*\//gs, "");

    const props = [];
    const propPattern =
        /(?:\/\*\*([^*]*(?:\*(?!\/)[^*]*)*)\*\/)?\s*([a-zA-Z_$][\w$]*)\??\s*:\s*([^;]+);/gs;

    for (const [, jsdoc, name, type] of cleaned.matchAll(propPattern)) {
        if (name && type) {
            props.push({
                name,
                type: cleanType(type),
                description: jsdoc ? cleanJSDoc(jsdoc) : "",
            });
        }
    }

    return props;
}

export function extractPropsFromExports(content) {
    const props = [];
    const exportPattern =
        /(?:\/\*\*([^*]*(?:\*(?!\/)[^*]*)*)\*\/)?\s*export\s+let\s+([\w$]+)\s*(?::\s*([^=;]+))?/gs;

    for (const [, jsdoc, name, type] of content.matchAll(exportPattern)) {
        props.push({
            name,
            type: type ? cleanType(type) : "any",
            description: jsdoc ? cleanJSDoc(jsdoc) : "",
        });
    }

    const asPattern =
        /let\s+([\w$]+)\s*=\s*[^;]+;\s*export\s*\{\s*\1\s+as\s+([\w$]+)\s*\}/gs;
    for (const [fullMatch, , exportName] of content.matchAll(asPattern)) {
        const beforeMatch = content.substring(0, content.indexOf(fullMatch));
        const jsdocMatch = beforeMatch.match(
            /\/\*\*([^*]*(?:\*(?!\/)[^*]*)*)\*\/\s*$/s
        );

        if (!props.find((p) => p.name === exportName)) {
            props.push({
                name: exportName,
                type: "string",
                description: jsdocMatch ? cleanJSDoc(jsdocMatch[1]) : "",
            });
        }
    }

    return props;
}

function extractProps(componentPath) {
    if (!existsSync(componentPath)) return null;

    const content = readFileSync(componentPath, "utf-8");
    let props = extractPropsFromInterface(content);
    if (props.length === 0) props = extractPropsFromExports(content);

    return props.length > 0 ? props : null;
}

export function extractStoryExamples(content) {
    const examples = [];

    // First, get component name from defineMeta
    const componentMatch = content.match(/component:\s*(\w+)/);
    const componentName = componentMatch ? componentMatch[1] : null;

    // Match both self-closing and regular Story tags
    const storyPattern =
        /<Story\s+name=["']([^"']+)["']([^>]*?)(?:\/>|>([\s\S]*?)<\/Story>)/g;

    for (const match of content.matchAll(storyPattern)) {
        const [, name, attrs, storyContent = ""] = match;

        if (storyContent.includes("<table") || storyContent.includes("{#each"))
            continue;

        let code = "";

        // Check if it's a self-closing tag with args
        if (attrs.includes("args=") && componentName) {
            const argsMatch = attrs.match(/args=\{\{([^}]+)\}\}/);
            if (argsMatch) {
                code = generateCodeFromArgs(componentName, argsMatch[1]);
            }
        } else if (storyContent) {
            // Match snippet with proper handling of nested braces in parameters
            const snippetMatch = storyContent.match(
                /\{#snippet\s+template(?:\([^)]*\))?\}([\s\S]*?)\{\/snippet\}/
            );
            code = snippetMatch ? snippetMatch[1] : storyContent;

            code = code
                .replace(/^\s*<div[^>]*>\s*\n/m, "")
                .replace(/\n\s*<\/div>\s*$/m, "")
                .replace(/\{\.\.\.args\}/g, "")
                .replace(/\{children \?\? ["']([^"']*)["']\}/g, "$1");

            const lines = code.split("\n").filter((l) => l.trim());
            if (lines.length === 0) continue;

            const minIndent = Math.min(
                ...lines.map((l) => l.match(/^\s*/)[0].length)
            );
            code = code
                .split("\n")
                .map((l) => l.slice(minIndent))
                .join("\n")
                .trim();
            code = code.replace(/\n{3,}/g, "\n\n");
        }

        if (code.length > 20 && code.length < 800) {
            examples.push({ name, code });
        }
    }

    return examples;
}

function generateCodeFromArgs(componentName, argsString) {
    // Parse args like: name: "example", src: "https://...", size: 64
    const props = [];
    const argPairs = argsString.split(",").map((s) => s.trim());

    for (const pair of argPairs) {
        const colonIdx = pair.indexOf(":");
        if (colonIdx === -1) continue;

        const key = pair.substring(0, colonIdx).trim();
        let value = pair.substring(colonIdx + 1).trim();

        // Remove quotes if present
        if (
            (value.startsWith('"') && value.endsWith('"')) ||
            (value.startsWith("'") && value.endsWith("'"))
        ) {
            value = value.slice(1, -1);
            props.push(`${key}="${value}"`);
        } else if (value === "true") {
            props.push(key);
        } else if (value === "false") {
            // Skip false boolean props
        } else {
            props.push(`${key}={${value}}`);
        }
    }

    return `<${componentName} ${props.join(" ")} />`;
}

function extractDocsFromStory(filePath) {
    if (!existsSync(filePath)) return null;

    const content = readFileSync(filePath, "utf-8");
    const jsdocMatches = content.match(/\/\*\*\s*\n([^*]|\*[^/])*\*\//g);
    const description = jsdocMatches
        ? jsdocMatches[jsdocMatches.length - 1]
              .replace(/\/\*\*|\*\//g, "")
              .replace(/^\s*\*\s?/gm, "")
              .trim()
        : "";

    return { description, examples: extractStoryExamples(content) };
}

function parseMDXDocs(mdxPath) {
    if (!existsSync(mdxPath)) return null;

    const content = readFileSync(mdxPath, "utf-8");
    const titleMatch = content.match(/<Title>([^<]+)<\/Title>/);
    const descMatch = content.match(
        /<Title>[^<]+<\/Title>\s*([\s\S]*?)(?=###|<PureArgsTable|<Canvas|$)/
    );

    const description = descMatch
        ? descMatch[1]
              .replace(/<[^>]+>/g, "")
              .replace(/\n{3,}/g, "\n\n")
              .trim()
        : "";

    const apiSections = [];
    const sectionPattern = /###\s+([^\n]+)\s*([\s\S]*?)(?=###|<Stories|$)/g;

    for (const [, title, sectionContent] of content.matchAll(sectionPattern)) {
        const argsMatch = sectionContent.match(
            /<PureArgsTable\s+rows=\{\{([\s\S]*?)\}\}\s*\/>/
        );
        if (argsMatch) {
            apiSections.push({
                title: title.trim(),
                props: parseArgsTable(argsMatch[1]),
            });
        }
    }

    return { title: titleMatch?.[1].trim() || "", description, apiSections };
}

export function parseArgsTable(argsContent) {
    const props = [];
    let depth = 0,
        currentProp = "";
    const propStrings = [];

    for (const char of argsContent) {
        if (char === "{") depth++;
        if (char === "}") depth--;
        if (char === "," && depth === 0) {
            if (currentProp.trim()) propStrings.push(currentProp.trim());
            currentProp = "";
        } else {
            currentProp += char;
        }
    }
    if (currentProp.trim()) propStrings.push(currentProp.trim());

    for (const propString of propStrings) {
        const colonIdx = propString.indexOf(":");
        if (colonIdx === -1) continue;

        const propContent = propString.substring(colonIdx + 1).trim();
        if (!propContent.startsWith("{")) continue;

        const name = propContent.match(/name:\s*["']([^"']+)["']/)?.[1] || "";
        let description =
            propContent.match(/description:\s*["']([^"']+)["']/)?.[1] || "";
        let type =
            propContent.match(/type:\s*\{\s*name:\s*["']([^"']+)["']/)?.[1] ||
            "any";

        const valueMatch = propContent.match(/value:\s*\[([^\]]+)\]/);
        if (valueMatch) {
            const values = valueMatch[1].match(/["']([^"']+)["']/g);
            if (values)
                type = values.map((v) => v.replace(/["']/g, "")).join(" \\| ");
        }

        const defaultValue = propContent.match(
            /defaultValue:\s*\{\s*summary:\s*["']([^"']+)["']/
        )?.[1];
        if (defaultValue) {
            description = description
                ? `${description} (default: ${defaultValue})`
                : `Default: ${defaultValue}`;
        }

        if (propContent.includes("required: true")) type = `${type} (required)`;

        props.push({ name, type, description });
    }

    return props;
}

function findSubcomponents(componentPath) {
    const componentDir = dirname(componentPath);
    const mainFile = basename(componentPath);

    return readdirSync(componentDir)
        .filter(
            (file) =>
                file.endsWith(".svelte") &&
                file !== mainFile &&
                !file.includes(".stories.") &&
                !file.includes(".test.")
        )
        .map((file) => ({
            name: basename(file, ".svelte"),
            path: join(componentDir, file),
        }));
}

function generateDocs(groups) {
    let md = `# ${summaryTitle}\n\n${summaryDescription}\n\n`;
    md += `> Generated Storybook documentation optimized for LLM consumption.\n\n---\n\n## Table of Contents\n\n`;

    groups.forEach((group, idx) => {
        if (group.docs) {
            md += `${idx + 1}. [${group.title}](#${group.title.toLowerCase().replace(/[/\s]/g, "-")})\n`;
        }
    });

    md += `\n---\n\n`;

    for (const group of groups) {
        if (!group.docs) continue;

        md += `## ${group.title}\n\n`;

        let storyDocs = null;
        let mdxDocs = null;
        let props = null;
        let componentPath = null;

        if (group.importPath) {
            const sourceFile = join(
                __dirname,
                "../src",
                group.importPath.replace(/^\.\//, "").replace(/^src\//, "")
            );
            storyDocs = extractDocsFromStory(sourceFile);
            componentPath = sourceFile.replace(/\.stories\.svelte$/, ".svelte");

            if (existsSync(componentPath)) {
                props = extractProps(componentPath);
            }

            const mdxPath = sourceFile.replace(/\.stories\.svelte$/, ".mdx");
            if (existsSync(mdxPath)) {
                mdxDocs = parseMDXDocs(mdxPath);
            }
        }

        if (mdxDocs?.description) md += `${mdxDocs.description}\n\n`;
        else if (storyDocs?.description) md += `${storyDocs.description}\n\n`;

        md += `**View in Storybook:** [${summaryBaseUrl}/?path=/docs/${group.docs.id}](${summaryBaseUrl}/?path=/docs/${group.docs.id})\n\n`;

        if (mdxDocs?.apiSections?.length) {
            md += `### API\n\n`;
            for (const section of mdxDocs.apiSections) {
                md += `#### ${section.title}\n\n`;
                if (section.props?.length) {
                    md += `| Parameter | Type | Description |\n|-----------|------|-------------|\n`;
                    for (const { name, type, description } of section.props) {
                        md += `| \`${name}\` | \`${type.replace(/\|/g, "\\|")}\` | ${description || "-"} |\n`;
                    }
                    md += `\n`;
                }
            }
        }

        if (storyDocs?.examples?.length) {
            md += `### Usage Examples\n\n`;
            for (const { name, code } of storyDocs.examples) {
                md += `**${name}:**\n\n\`\`\`svelte\n${code}\n\`\`\`\n\n`;
            }
        }

        if (props?.length) {
            md += `### Props\n\n| Prop | Type | Description |\n|------|------|-------------|\n`;
            for (const { name, type, description } of props) {
                md += `| \`${name}\` | \`${type.replace(/\|/g, "\\|")}\` | ${description || "-"} |\n`;
            }
            md += `\n`;
        }

        if (componentPath && existsSync(componentPath)) {
            const subcomponents = findSubcomponents(componentPath);
            if (subcomponents.length) {
                md += `### Subcomponents\n\n`;
                for (const { name, path } of subcomponents) {
                    md += `#### ${name}\n\n`;
                    const subProps = extractProps(path);
                    if (subProps?.length) {
                        md += `| Prop | Type | Description |\n|------|------|-------------|\n`;
                        for (const { name, type, description } of subProps) {
                            md += `| \`${name}\` | \`${type.replace(/\|/g, "\\|")}\` | ${description || "-"} |\n`;
                        }
                        md += `\n`;
                    }
                }
            }
        }

        if (group.stories?.length) {
            md += `### Story Variations (${group.stories.length})\n\n`;
            for (const { name, id } of group.stories) {
                md += `- **${name}**: [View](${summaryBaseUrl}/?path=/story/${id})\n`;
            }
            md += `\n`;
        }

        md += `---\n\n`;
    }

    md += `## Generation Info\n\n`;
    md += `- **Generated:** ${new Date().toISOString()}\n`;
    md += `- **Components:** ${groups.filter((g) => g.docs).length}\n`;
    md += `- **Stories:** ${groups.reduce((sum, g) => sum + g.stories.length, 0)}\n`;

    return md;
}

async function main() {
    console.log("━━ Storybook LLM Docs Generator ━━\n");

    const absoluteDistPath = join(__dirname, distPath);
    console.log(`📍 Dist: ${absoluteDistPath}`);
    console.log(`📍 Source: ${__dirname}/../src`);
    console.log(`🌿 Branch: ${currentBranch}`);
    console.log(`🔗 Base URL: ${summaryBaseUrl}\n`);

    console.log("📖 Reading index.json...");
    const index = parseStorybookIndex(absoluteDistPath);
    const groups = groupStoriesByComponent(index.entries);
    console.log(`✓ Found ${groups.length} component groups\n`);

    console.log("📄 Extracting documentation...");
    const docs = generateDocs(groups);

    const outputPath = join(absoluteDistPath, "llms.txt");
    writeFileSync(outputPath, docs, "utf-8");

    console.log(
        `✓ Generated ${outputPath} (${(docs.length / 1024).toFixed(1)} KB)\n`
    );
    console.log("✅ Done!\n");
}

main().catch((error) => {
    console.error("❌ Error:", error.message);
    process.exit(1);
});
